import React, { useState, useEffect, Suspense, lazy } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import * as actions from '../../redux/actions';

import {
  Box,
  Button,
  Paper,
  Typography,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Switch,
  IconButton,
  Modal,
  TextField,
  Alert,
  CircularProgress,
  Tooltip,
  TablePagination,
} from '@mui/material';

import EditIcon from '@mui/icons-material/Edit';
import LocationOnIcon from '@mui/icons-material/LocationOn';
import SaveIcon from '@mui/icons-material/Save';
import CloseIcon from '@mui/icons-material/Close';

const HrCheckinManagementMap = lazy(() =>
  import('./HrCheckinManagementMap'),
);

const DEFAULT_CENTER = { lat: 13.7563, lng: 100.5018 };
const DEFAULT_ZOOM = 14;
const PAGE_SIZE = 50;

const MapMarker = () => (
  <Box
    sx={{
      position: 'absolute',
      transform: 'translate(-50%, -100%)',
      color: '#d32f2f',
      fontSize: 36,
    }}
  >
    <LocationOnIcon sx={{ fontSize: 40 }} />
  </Box>
);

const modalStyle = {
  position: 'absolute',
  top: '50%',
  left: '50%',
  transform: 'translate(-50%, -50%)',
  width: { xs: '95%', sm: 480 },
  maxWidth: 480,
  maxHeight: '90vh',
  overflow: 'auto',
  bgcolor: 'background.paper',
  borderRadius: 2,
  boxShadow: 24,
  p: 3,
};

export default function HrCheckinManagement({ title, subtitle }) {
  const dispatch = useDispatch();
  const project = useSelector((state) => state.project);
  const me = useSelector((state) => state.me);

  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(0);
  const [editModalOpen, setEditModalOpen] = useState(false);
  const [editingProject, setEditingProject] = useState(null);
  const [editLocation, setEditLocation] = useState('');
  const [editLat, setEditLat] = useState('');
  const [editLon, setEditLon] = useState('');
  const [saving, setSaving] = useState(false);
  const [mapCenter, setMapCenter] = useState(DEFAULT_CENTER);
  const [message, setMessage] = useState({ type: null, text: '' });

  const total = project?.total ?? 0;

  useEffect(() => {
    setLoading(true);
    dispatch(
      actions.projectAll({ size: PAGE_SIZE, page: page + 1 }),
    ).then(() => setLoading(false));
  }, [dispatch, page]);

  useEffect(() => {
    const list = project?.rows ?? [];
    setProjects(Array.isArray(list) ? list : []);
  }, [project]);

  const handleToggleTimeTracking = async (row, checked) => {
    const confirmMsg = checked
      ? 'เปิดการลงเวลาสำหรับโครงการนี้?'
      : 'ปิดการลงเวลาสำหรับโครงการนี้?';
    if (!window.confirm(confirmMsg)) return;
    try {
      await dispatch(
        actions.projectPut(row.id || row._id, {
          time_tracking_enabled: checked,
        }),
      );
      await dispatch(actions.projectAll({ size: PAGE_SIZE, page: page + 1 }));
      setMessage({ type: 'success', text: 'อัปเดตสถานะการลงเวลาแล้ว' });
      setTimeout(() => setMessage({ type: null, text: '' }), 3000);
    } catch (err) {
      setMessage({ type: 'error', text: 'อัปเดตไม่สำเร็จ' });
      setTimeout(() => setMessage({ type: null, text: '' }), 3000);
    }
  };

  const openEditModal = (row) => {
    setEditingProject(row);
    setEditLocation(row.location || '');
    const lat = row.gps?.lat != null ? String(row.gps.lat) : '';
    const lon = row.gps?.lon != null ? String(row.gps.lon) : '';
    setEditLat(lat);
    setEditLon(lon);
    setMapCenter(
      lat && lon
        ? { lat: parseFloat(lat), lng: parseFloat(lon) }
        : DEFAULT_CENTER,
    );
    setEditModalOpen(true);
  };

  const closeEditModal = () => {
    setEditModalOpen(false);
    setEditingProject(null);
    setEditLocation('');
    setEditLat('');
    setEditLon('');
    setMapCenter(DEFAULT_CENTER);
  };

  const handleSaveLocation = async () => {
    if (!editingProject) return;
    const id = editingProject.id || editingProject._id;
    const lat = editLat.trim() ? parseFloat(editLat) : undefined;
    const lon = editLon.trim() ? parseFloat(editLon) : undefined;
    const payload = {
      location: editLocation.trim() || undefined,
      gps: lat != null && lon != null ? { lat, lon } : undefined,
    };
    if (!payload.location && !payload.gps) {
      setMessage({ type: 'warning', text: 'กรุณากรอกสถานที่หรือพิกัด GPS' });
      return;
    }
    setSaving(true);
    try {
      await dispatch(actions.projectPut(id, payload));
      await dispatch(actions.projectAll({ size: PAGE_SIZE, page: page + 1 }));
      setMessage({ type: 'success', text: 'บันทึกโลเคชั่นแล้ว' });
      setTimeout(() => setMessage({ type: null, text: '' }), 3000);
      closeEditModal();
    } catch (err) {
      setMessage({ type: 'error', text: 'บันทึกไม่สำเร็จ' });
      setTimeout(() => setMessage({ type: null, text: '' }), 3000);
    } finally {
      setSaving(false);
    }
  };

  const gpsText = (row) => {
    const g = row.gps;
    if (!g || (g.lat == null && g.lon == null)) return '-';
    return `${g.lat != null ? Number(g.lat).toFixed(5) : '-'}, ${
      g.lon != null ? Number(g.lon).toFixed(5) : '-'
    }`;
  };

  if (loading) {
    return (
      <Box
        display="flex"
        justifyContent="center"
        alignItems="center"
        minHeight={320}
      >
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box>
      <Box mb={2}>
        <Typography variant="body2" color="text.secondary">
          เปิด/ปิดการลงเวลาแต่ละโครงการ และจัดการโลเคชั่น (สถานที่ / GPS)
        </Typography>
      </Box>

      {message.text && (
        <Alert
          severity={message.type || 'info'}
          sx={{ mb: 2 }}
          onClose={() => setMessage({ type: null, text: '' })}
        >
          {message.text}
        </Alert>
      )}

      <TableContainer component={Paper} elevation={1} sx={{ borderRadius: 2 }}>
        <Table size="small">
          <TableHead>
            <TableRow sx={{ bgcolor: 'grey.100' }}>
              <TableCell sx={{ fontWeight: 600 }}>เลขที่งาน</TableCell>
              <TableCell sx={{ fontWeight: 600 }}>โครงการ</TableCell>
              <TableCell sx={{ fontWeight: 600 }}>สถานที่ (Location)</TableCell>
              <TableCell sx={{ fontWeight: 600 }}>
                พิกัด GPS (lat, lon)
              </TableCell>
              <TableCell align="center" sx={{ fontWeight: 600 }}>
                เปิดลงเวลา
              </TableCell>
              <TableCell align="center" sx={{ fontWeight: 600 }}>
                จัดการ
              </TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {projects.length === 0 ? (
              <TableRow>
                <TableCell colSpan={6} align="center" sx={{ py: 4 }}>
                  ไม่มีโครงการ
                </TableCell>
              </TableRow>
            ) : (
              projects.map((row) => (
                <TableRow key={row.id || row._id} hover>
                  <TableCell>
                    <Typography variant="body2" fontFamily="monospace">
                      {row.project_number || '-'}
                    </Typography>
                  </TableCell>
                  <TableCell>
                    <Typography variant="body2" fontWeight={500}>
                      {row.name || '-'}
                    </Typography>
                    {row.customer && (
                      <Typography variant="caption" color="text.secondary">
                        {row.customer}
                      </Typography>
                    )}
                  </TableCell>
                  <TableCell>
                    {row.location ? (
                      <Typography variant="body2">{row.location}</Typography>
                    ) : (
                      <Typography variant="body2" color="text.secondary">
                        -
                      </Typography>
                    )}
                  </TableCell>
                  <TableCell>
                    <Typography variant="body2" fontFamily="monospace">
                      {gpsText(row)}
                    </Typography>
                  </TableCell>
                  <TableCell align="center">
                    <Switch
                      checked={Boolean(row.time_tracking_enabled)}
                      onChange={(e) =>
                        handleToggleTimeTracking(row, e.target.checked)
                      }
                      color="primary"
                      size="small"
                    />
                  </TableCell>
                  <TableCell align="center">
                    <Tooltip title="แก้ไขโลเคชั่น">
                      <IconButton
                        size="small"
                        color="primary"
                        onClick={() => openEditModal(row)}
                      >
                        <EditIcon fontSize="small" />
                      </IconButton>
                    </Tooltip>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
        <TablePagination
          component="div"
          count={total}
          page={page}
          onPageChange={(_, newPage) => setPage(newPage)}
          rowsPerPage={PAGE_SIZE}
          rowsPerPageOptions={[PAGE_SIZE]}
          labelDisplayedRows={({ from, to, count }) =>
            `${from}–${to} จาก ${count}`
          }
        />
      </TableContainer>

      <Modal open={editModalOpen} onClose={closeEditModal}>
        <Box sx={modalStyle}>
          <Box
            display="flex"
            alignItems="center"
            justifyContent="space-between"
            mb={2}
          >
            <Typography variant="h6">
              <LocationOnIcon sx={{ mr: 1, verticalAlign: 'middle' }} />
              แก้ไขโลเคชั่น
            </Typography>
            <IconButton size="small" onClick={closeEditModal}>
              <CloseIcon />
            </IconButton>
          </Box>
          {editingProject && (
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              เลขที่งาน: {editingProject.project_number || '-'} · โครงการ: {editingProject.name}
            </Typography>
          )}

          <Typography variant="subtitle2" color="text.secondary" sx={{ mb: 1 }}>
            คลิกบนแผนที่เพื่อเลือกตำแหน่ง
          </Typography>
          <Box
            sx={{
              height: 220,
              borderRadius: 2,
              overflow: 'hidden',
              mb: 2,
              border: '1px solid',
              borderColor: 'divider',
            }}
          >
            <Suspense
              fallback={
                <Box
                  display="flex"
                  alignItems="center"
                  justifyContent="center"
                  height="100%"
                  minHeight={220}
                >
                  <CircularProgress size={32} />
                </Box>
              }
            >
              <HrCheckinManagementMap
                center={mapCenter}
                zoom={DEFAULT_ZOOM}
                apiKey={process.env.REACT_APP_MAP_API_KEY}
                onClick={({ lat, lng }) => {
                  setEditLat(lat.toFixed(6));
                  setEditLon(lng.toFixed(6));
                  setMapCenter({ lat, lng });
                }}
              >
                {editLat && editLon && (
                  <MapMarker
                    lat={parseFloat(editLat)}
                    lng={parseFloat(editLon)}
                  />
                )}
              </HrCheckinManagementMap>
            </Suspense>
          </Box>

          <TextField
            fullWidth
            label="สถานที่ (Location)"
            value={editLocation}
            onChange={(e) => setEditLocation(e.target.value)}
            size="small"
            sx={{ mb: 2 }}
            placeholder="ชื่อสถานที่หรือที่อยู่"
          />
          <TextField
            fullWidth
            label="ละติจูด (Lat)"
            value={editLat}
            onChange={(e) => setEditLat(e.target.value)}
            size="small"
            type="number"
            inputProps={{ step: 0.00001 }}
            sx={{ mb: 2 }}
            placeholder="เช่น 13.7563"
          />
          <TextField
            fullWidth
            label="ลองจิจูด (Lon)"
            value={editLon}
            onChange={(e) => setEditLon(e.target.value)}
            size="small"
            type="number"
            inputProps={{ step: 0.00001 }}
            sx={{ mb: 2 }}
            placeholder="เช่น 100.5018"
          />
          <Box display="flex" justifyContent="flex-end" gap={1} mt={2}>
            <Button variant="outlined" onClick={closeEditModal} size="small">
              ยกเลิก
            </Button>
            <Button
              variant="contained"
              startIcon={saving ? <CircularProgress size={16} /> : <SaveIcon />}
              onClick={handleSaveLocation}
              disabled={saving}
              size="small"
            >
              บันทึก
            </Button>
          </Box>
        </Box>
      </Modal>
    </Box>
  );
}
